import { Link } from 'react-router-dom'
import { defaultLang } from '../i18n/translations'
import { useTranslation } from '../i18n/useTranslation'
import { useEffect } from 'react'
import { SeoHead } from '../components/SeoHead'
import './HomePage.css'
import './ComingSoonPage.css'

function ComingSoonPage() {
  const lang = defaultLang
  const t = useTranslation(lang)

  useEffect(() => {
    document.documentElement.lang = lang
  }, [lang])

  return (
    <div className="coming-soon-page home-page">
      <SeoHead title={t('corporate.comingSoonTitle')} description={t('corporate.comingSoonDesc')} />
      <main className="coming-soon-main">
        <h1 className="coming-soon-title">{t('corporate.comingSoonTitle')}</h1>
        <p className="coming-soon-text">{t('corporate.comingSoonDesc')}</p>
        <Link to="/" className="coming-soon-btn">{t('corporate.backHome')}</Link>
      </main>
    </div>
  )
}

export default ComingSoonPage
